mapper.select:
SELECT C.*
FROM
	(
		SELECT B.*, ROWNUM
		FROM
			(
				SELECT

				FROM BIF.TB_UPLOAD A

				ORDER BY A.seq desc
			) B
		WHERE ROWNUM <= #{lastIndex}
	) C
WHERE C.ROWNUM >= #{firstIndex}

SELECT COUNT(1) FROM BIF.TB_NEWZIPCODE 
WHERE zipcode=#{zipcode} 
and roadnameid=#{roadnameid} 
and bldg_mainno=#{bldg_mainno} 
and bldg_subno=#{bldg_subno} 
and bldgmgmtid=#{bldgmgmtid}
and bldgname=#{bldgname}
and jibun_bonbun=#{jibun_bonbun} 
and jibun_bubun=#{jibun_bubun}

choose.when:
