SET zipcode=#{zipcode},
	sido=#{sido},
	sigungu=#{sigungu},
	town=#{town},
	roadnameid=#{roadnameid},
	roadname=#{roadname},
	bldg_mainno=#{bldg_mainno},
	bldg_subno=#{bldg_subno},
	bldgmgmtid=#{bldgmgmtid},
	bldgname=#{bldgname},
	ri=#{ri},
	legal_dong=#{legal_dong},
	dong=#{dong},
	jibun_bonbun=#{jibun_bonbun},
	jibun_bubun=#{jibun_bubun}
WHERE zipcode=#{zipcode} 
	and roadnameid=#{roadnameid} 
	and bldg_mainno=#{bldg_mainno} 
	and bldg_subno=#{bldg_subno} 
